10	};
11	
12	const PROCESSING_FEE = 5;
13	
14	const BASE_PREMIUMS: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	  rune: 25,
20	  moonstone: 25,
21	};
22	
23	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
24	const BLOCK_SIZE = 3;
25	const BLOCK_PREMIUM = 60;
26	const CURSE_SURCHARGE_RATE = 0.5;
27	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
28	const HIGH_ENCHANTMENT_THRESHOLD = 5;
29	const FIRST_INSURANCE_RATE = 0.1;
30	const LOYALTY_DISCOUNT_RATE = 0.2;
31	const LOYALTY_YEARS_THRESHOLD = 2;
32	const FOLLOWUP_DISCOUNT_RATE = 0.15;
33	const DEDUCTIBLE = 100;
34	
35	function itemSurcharge(item: Item): number {
36	  const itemBase = BASE_PREMIUMS[item.type];
37	  let surcharge = 0;
38	  if (item.cursed) surcharge += itemBase * CURSE_SURCHARGE_RATE;
39	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
40	    surcharge += itemBase * HIGH_ENCHANTMENT_SURCHARGE_RATE;
41	  }
42	  return surcharge;
43	}
44	
45	function typeSubtotal(type: string, count: number): number {
46	  const isBlock = COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
47	  return isBlock ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
48	}
49	
50	function loyaltyDiscount(customer: Customer, policyBase: number): number {
51	  return customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
52	    ? policyBase * LOYALTY_DISCOUNT_RATE
53	    : 0;
54	}
55	
56	function followupDiscount(customer: Customer, policyBase: number): number {
57	  return customer.previousContracts >= 1
58	    ? policyBase * FOLLOWUP_DISCOUNT_RATE
59	    : 0;
60	}
61	
62	export type Damage = {
63	  itemType: string;
64	  amount: number;
65	};
66	
67	export function claim(items: Item[], damages: Damage[]): { payout: number } {
68	  const totalPayout = damages.reduce((sum, d) => {
69	    const item = items.find((i) => i.type === d.itemType);
70	    const reimbursed = (item && (item.enchantment ?? 0) >= 8) ? 0.5 * d.amount : d.amount;
71	    return sum + Math.max(0, reimbursed - DEDUCTIBLE);
72	  }, 0);
73	  return { payout: Math.floor(totalPayout) };
74	}
75	
76	export function quote(customer: Customer, items: Item[]): number {
77	  const countsByType: Record<string, number> = {};
78	  for (const item of items) {
79	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
80	  }
81	
82	  const policyBase = Object.entries(countsByType)
83	    .reduce((sum, [type, count]) => sum + typeSubtotal(type, count), 0);
84	
85	  const itemSurcharges = items.reduce((sum, item) => sum + itemSurcharge(item), 0);
86	  const loyalty = loyaltyDiscount(customer, policyBase);
87	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
88	  const followup = followupDiscount(customer, policyBase);
89	
90	  return Math.ceil(policyBase + itemSurcharges - loyalty + firstInsurance - followup) + PROCESSING_FEE;
91	}
